const prospects = $input.first().json;
const now = new Date();

if (!Array.isArray(prospects) || prospects.length === 0) {
  return [{ json: { hasWork: false, summary: 'Нет активных проспектов', count: 0 } }];
}

// Разбиваем по стадиям
const toContact = [];
const toInvite = [];
const toCheckRegistered = [];

for (const p of prospects) {
  const nextFollowup = p.next_followup_at ? new Date(p.next_followup_at) : null;
  const needsAction = !nextFollowup || nextFollowup <= now;

  if (!needsAction) continue;

  if (p.stage === 'new') {
    toContact.push(p);
  } else if (p.stage === 'messaged' || p.stage === 'replied') {
    // Follow-up в Авито — напоминаем об ответе
    toContact.push(p);
  } else if (p.stage === 'contact_collected' || p.stage === 'invite_sent') {
    toInvite.push(p);
  }

  toCheckRegistered.push(p);
}

return [{ json: {
  hasWork: true,
  toContact,
  toInvite,
  toCheckRegistered,
  totalProspects: prospects.length,
  summary: `Проспекты: ${prospects.length} / К контакту: ${toContact.length} / К инвайту: ${toInvite.length}`
} }];

const data = $input.first().json;
const toContact = data.toContact || [];
const toInvite = data.toInvite || [];

// Генерируем Авито-сообщения для каждого проспекта
const SPECIALTY_MAP = {
  'demolition': 'снос и демонтаж',
  'painting': 'малярно-штукатурные работы',
  'electrical': 'электромонтажные работы',
  'plumbing': 'сантехника',
  'tiling': 'плиточные работы',
  'flooring': 'напольные покрытия',
  'carpentry': 'плотницкие работы',
  'roofing': 'кровельные работы',
  'general': 'общестроительные работы',
  'landscaping': 'благоустройство территории'
};

const AVITO_MESSAGES = {
  new: (p) => {
    const city = p.city === 'novosibirsk' ? 'Новосибирске' : 'Омске';
    const specs = (p.specialties || []).map(s => SPECIALTY_MAP[s] || s).join(', ');
    return `Здравствуйте! Меня зовут Алексей, я представляю сервис Подряд PRO — мы помогаем мастерам находить клиентов в ${city}.\n\nВижу, что вы занимаетесь ${specs || 'строительными работами'}. У нас сейчас есть запросы от заказчиков именно по вашей специализации.\n\nПлатформа полностью бесплатна для исполнителей — вы получаете заказы и выбираете подходящие. Расскажите подробнее, как вы сейчас работаете? Интересно было бы сотрудничать?`;
  },
  messaged: (p) => {
    return `Добрый день! Писал вам ранее по поводу сервиса Подряд PRO. Хотел уточнить — получили моё сообщение? Есть актуальные заказы в вашем районе, хотел бы поделиться деталями.`;
  },
  replied: (p) => {
    return `Отлично, что ответили! Для регистрации на платформе нужно всего 5 минут. Могу прислать ссылку на регистрацию удобным способом — WhatsApp, Telegram или SMS. Как лучше?`;
  }
};

const INVITE_MESSAGES = {
  contact_collected: (p) => {
    const city = p.city === 'novosibirsk' ? 'Новосибирске' : 'Омске';
    return `🏗 Подряд PRO приглашает вас присоединиться!\n\nВы общались с нашим представителем насчёт заказов в ${city}.\n\n✅ Регистрация бесплатная\n✅ Выбираете только подходящие заказы\n✅ Оплата гарантирована эскроу-сервисом\n\nЗарегистрироваться за 2 минуты:`;
  },
  invite_sent: (p) => {
    return `Напоминаю о регистрации на Подряд PRO — ссылку отправлял раньше. Сейчас в системе есть заказы по вашей специализации. Зарегистрируйтесь — первый заказ подберём лично! 🤝`;
  }
};

const contactMessages = toContact.map(p => ({
  ...p,
  avitoMessage: (AVITO_MESSAGES[p.stage] || AVITO_MESSAGES.messaged)(p),
  action: 'avito_message'
}));

const inviteMessages = toInvite.map(p => ({
  ...p,
  inviteMessage: (INVITE_MESSAGES[p.stage] || INVITE_MESSAGES.contact_collected)(p),
  regLink: `https://app.podryad.pro/join?ref=avito&phone=${p.phone || ''}`,
  action: 'send_invite'
}));

return [{ json: { contactMessages, inviteMessages, data } }];

const data = $input.first().json;
const contactMessages = data.contactMessages || [];
const inviteMessages = data.inviteMessages || [];

if (contactMessages.length === 0 && inviteMessages.length === 0) {
  return [{ json: { skipped: true } }];
}

// Формируем единый отчёт для администратора
let report = `🤖 *CRM Агент — Исполнители Авито*\n\nДата: ${new Date().toLocaleString('ru-RU')}\n`;
report += `\n📊 Обработано проспектов: ${data.data?.totalProspects || 0}`;

if (contactMessages.length > 0) {
  report += `\n\n📨 *Написать в Авито (${contactMessages.length})*:`;
  for (const p of contactMessages.slice(0, 5)) {
    report += `\n\n👷 ${p.name || 'Без имени'}`;
    if (p.avito_profile_url) report += `\n🔗 ${p.avito_profile_url}`;
    report += `\n📋 Специализация: ${(p.specialties || []).join(', ') || 'не указана'}`;
    report += `\n\n*Текст сообщения:*\n${p.avitoMessage}`;
    report += `\n${'─'.repeat(20)}`;
  }
  if (contactMessages.length > 5) {
    report += `\n\n...и ещё ${contactMessages.length - 5} проспектов`;
  }
}

if (inviteMessages.length > 0) {
  report += `\n\n📲 *Отправить регистрационную ссылку (${inviteMessages.length})*:`;
  for (const p of inviteMessages.slice(0, 5)) {
    report += `\n\n👷 ${p.name || 'Без имени'}`;
    if (p.phone) report += ` | Тел: ${p.phone}`;
    report += `\n🔗 Ссылка: ${p.regLink}`;
    report += `\n\n*Текст:*\n${p.inviteMessage}\n${p.regLink}`;
    report += `\n${'─'.repeat(20)}`;
  }
}

return [{ json: { report, contactCount: contactMessages.length, inviteCount: inviteMessages.length, contactMessages, inviteMessages } }];

const data = $input.first().json;
const contactMessages = data.contactMessages || [];
const inviteMessages = data.inviteMessages || [];
const allToProcess = [...contactMessages, ...inviteMessages];

// Обновляем стадии для каждого проспекта
const updates = [];
const now = new Date();

for (const p of allToProcess) {
  let newStage = p.stage;
  let nextFollowup = null;

  if (p.stage === 'new') {
    newStage = 'messaged';
    nextFollowup = new Date(now.getTime() + 48 * 3600 * 1000).toISOString(); // +48h
  } else if (p.stage === 'messaged') {
    newStage = 'messaged'; // Остаётся, увеличиваем счётчик
    nextFollowup = new Date(now.getTime() + 72 * 3600 * 1000).toISOString(); // +72h
  } else if (p.stage === 'contact_collected') {
    newStage = 'invite_sent';
    nextFollowup = new Date(now.getTime() + 48 * 3600 * 1000).toISOString(); // +48h
  } else if (p.stage === 'invite_sent') {
    nextFollowup = new Date(now.getTime() + 7 * 24 * 3600 * 1000).toISOString(); // +7 days
  }

  updates.push({
    id: p.id,
    stage: newStage,
    contact_attempts: (p.contact_attempts || 0) + 1,
    last_contacted_at: now.toISOString(),
    next_followup_at: nextFollowup,
    updated_at: now.toISOString()
  });
}

return [{ json: { updates, count: updates.length } }];

const { updates } = $input.first().json;
// Split into individual items for SplitInBatches
return updates.map(u => ({ json: u }));

const inviteSentProspects = $input.first().json;
if (!Array.isArray(inviteSentProspects) || inviteSentProspects.length === 0) {
  return [{ json: { registrations: [] } }];
}

// Проверяем каждого: есть ли в таблице contractors с этим телефоном?
const phones = inviteSentProspects.filter(p => p.phone).map(p => p.phone);
return [{ json: { toCheck: inviteSentProspects, phones } }];

const registeredContractors = $input.first().json;
if (!Array.isArray(registeredContractors) || registeredContractors.length === 0) {
  return [{ json: { newlyRegistered: [] } }];
}

const now = new Date().toISOString();
const updates = registeredContractors.map(c => ({
  phone: c.phone,
  contractor_id: c.id,
  update: { stage: 'registered', registered_at: now, contractor_id: c.id, updated_at: now }
}));

return [{ json: { newlyRegistered: registeredContractors, updates } }];

